      {
        "method": "GET",
        "path": "/api/courses",
        "purpose": "Fetch course data"
      },
      {
        "method": "GET",
        "path": "/api/student-performance",
        "purpose": "Fetch student performance metrics"
      },
      {
        "method": "GET",
        "path": "/api/reports",
        "purpose": "Fetch available reports"
      }
    ]
  },
  "database": {
    "tables": [
