        "name": "courses",
        "columns": [
          "id",
          "course_name",
          "department",
          "semester"
        ]
      },
      {
        "name": "student_performance",
        "columns": [
          "id",
          "course_id",
          "student_id",
          "attendance_rate",
          "midterm_score",
          "final_score"
        ]
      },
      {
        "name": "reports",
        "columns": [
          "id",
          "title",
          "description",
          "download_link"
        ]
      }
    ]
  },
  "auth_required": true
